# Azure AD admins can control:

# 1. Restrict non-admin users from accessing Azure portal
az rest \
  --method PATCH \
  --uri "https://graph.microsoft.com/v1.0/policies/authorizationPolicy" \
  --body '{"allowedToSignUpEmailBasedSubscriptions": false}' \
  --headers "Content-Type=application/json"

# 2. Set the MFA registration campaign (nudge users to register MFA)
# Done via: Azure AD > Security > Authentication methods > Registration campaign

# 3. Force sign-in frequency (e.g. re-auth every 8 hours) via Conditional Access
az rest \
  --method POST \
  --uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies" \
  --body '{
    "displayName": "Portal session control - 8h re-auth",
    "state": "enabled",
    "conditions": {
      "applications": {"includeApplications": ["00000000-0000-0000-0000-000000000000"]},
      "users": {"includeGroups": ["all-users-group-id"]}
    },
    "sessionControls": {
      "signInFrequency": {"value": 8, "type": "hours", "isEnabled": true}
    }
  }' \
  --headers "Content-Type=application/json"
